+            0.958_687_724_771_348_3,
+            1.109_617_078_863_06,
+        ];
+        assert_f64_seq("random_state_weibull_shaped", &values, &expected);
+        let after: Vec<u64> = (0..5).map(|_| shaped.random_interval(9)).collect();
